+fn apply_diff(base: &Buffer, target: &Buffer, diff: &BufferDiff) -> Buffer {
+    let mut result = base.clone();
+    for (x, y) in diff.iter() {
+        let cell = *target.get_unchecked(x, y);
+        result.set_raw(x, y, cell);
+    }
+    result
+}
